/**
 * @name Path traversal in StaticHandlerImpl via taint flow
 * @description Taint tracking from HTTP request path to file system operation in StaticHandlerImpl
 * @kind path-problem
 * @problem.severity error
 * @id java/static-handler-path-traversal-taint
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // path() or normalizedPath() on HttpServerRequest
    exists(MethodCall mc |
      (mc.getMethod().hasName("path") or mc.getMethod().hasName("normalizedPath")) and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.core.http", "HttpServerRequest") and
      source.asExpr() = mc
    )
    or
    // normalizePath() result
    exists(MethodCall mc |
      mc.getMethod().hasName("normalizePath") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web.impl", "Utils") and
      source.asExpr() = mc
    )
    or
    // removeDots result
    exists(MethodCall mc |
      mc.getMethod().hasName("removeDots") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web.impl", "Utils") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // sendFile call in RoutingContext / HttpServerResponse
    exists(MethodCall mc |
      (mc.getMethod().hasName("sendFile") or mc.getMethod().hasName("sendStatic")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // getFile call in StaticHandlerImpl
    exists(MethodCall mc |
      mc.getMethod().hasName("getFile") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP request path flows to file operation without sufficient validation $@.", source.getNode(), "user-controlled path"
